async function getApods(){try{const t=await fetch("/apod/data/apod.local.json");apodData=await t.json(),renderPage(currentPage),renderPagination()}catch(t){console.error("Error loading APODs:",t),apodGallery.innerHTML="<p>Failed to load APOD data.</p>"}}function slugify(t){return t.toLowerCase().replace(/[^\w\s-]/g,"").replace(/\s+/g,"-").replace(/-+/g,"-")}function renderPage(t){apodGallery.innerHTML="";const e=(t-1)*perPage,a=apodData.slice(e,e+perPage);a.forEach((e,a)=>{const n=document.createElement("a");n.classList.add("apod-card");const r=slugify(e.title);n.href=`image/${r}`,n.rel="noopener",n.innerHTML=`\n            <div class="apod-thumb" style="aspect-ratio: 16/9; overflow: hidden;">\n              <img src="thumbs/${e.date}.webp" alt="${e.title}" width="480" height="270"\n                  ${0===a&&1===t?'fetchpriority="high"':'loading="lazy"'}\n                  decoding="async"\n                  style="object-fit: cover; width: 100%; height: 100%;">\n            </div>\n            <div class="apod-meta">\n              <p class="apod-date"><time datetime="${e.date}">${e.date}</time></p>\n              <div class="apod-title">${e.title}</div>\n            </div>\n          `,apodGallery.appendChild(n)})}function renderPagination(){function t(t,e,a=7){const n=Math.floor(a/2);let r=Math.max(1,t-n),i=r+a-1;i>e&&(i=e,r=Math.max(1,i-a+1));const o=[];for(let t=r;t<=i;t++)o.push(t);return o}const e=Math.ceil(apodData.length/perPage);paginationControls.innerHTML="";const a=document.createElement("div");a.className="pagination-scroll",a.setAttribute("role","navigation"),a.setAttribute("aria-label","Gallery pages");const n=document.createElement("button");n.textContent="Previous",n.setAttribute("aria-label","Go to previous page"),n.setAttribute("type","button"),n.classList.add("prev-next-button"),n.disabled=1===currentPage,n.onclick=(()=>{currentPage>1&&(currentPage--,renderPage(currentPage),renderPagination())}),a.appendChild(n);const r=7,i=t(currentPage,e,r);i.forEach(t=>{const e=document.createElement("button");e.textContent=t,e.className="page-button",t===currentPage&&(e.classList.add("active"),e.setAttribute("aria-current","page")),e.setAttribute("aria-label",`Go to page ${t}`),e.setAttribute("type","button"),e.onclick=(()=>{currentPage=t,renderPage(currentPage),renderPagination()}),a.appendChild(e)});const o=document.createElement("button");o.textContent="Next",o.setAttribute("aria-label","Go to next page"),o.setAttribute("type","button"),o.classList.add("prev-next-button"),o.disabled=currentPage===e,o.onclick=(()=>{currentPage<e&&(currentPage++,renderPage(currentPage),renderPagination())}),a.appendChild(o),paginationControls.appendChild(a)}const thumbBtn=document.getElementById("thumbViewBtn"),listBtn=document.getElementById("listViewBtn"),apodGallery=document.getElementById("apodGallery");thumbBtn.addEventListener("click",()=>{apodGallery.classList.remove("list-view"),apodGallery.classList.add("grid-view"),thumbBtn.classList.add("active"),listBtn.classList.remove("active")}),listBtn.addEventListener("click",()=>{apodGallery.classList.add("list-view"),apodGallery.classList.remove("grid-view"),thumbBtn.classList.remove("active"),listBtn.classList.add("active")});const paginationControls=document.getElementById("paginationControls"),perPage=12;let currentPage=1,apodData=[];getApods();